import { NavLink } from "react-router-dom";
import { useAuth, hasRole } from "../AuthContext";

export default function Sidebar() {
    const { user } = useAuth();
    const can = (...roles) => hasRole(user, ...roles);

    // Khai báo menu + vai trò được phép xem
    const items = [
        { to: "/",          text: "Tổng quan", roles: ["ADMIN","SALES","ACCOUNTANT"], icon: "📊" },
        { to: "/customers", text: "Khách hàng", roles: ["ADMIN","SALES"],            icon: "👥" },
        { to: "/contracts", text: "Hợp đồng",   roles: ["ADMIN","SALES","ACCOUNTANT"],icon: "📄" },
        { to: "/payments",  text: "Thanh toán", roles: ["ADMIN","ACCOUNTANT"],       icon: "💳" },
        { to: "/events",    text: "Sự kiện",    roles: ["ADMIN","SALES"],            icon: "📅" },
        { to: "/users",     text: "Người dùng", roles: ["ADMIN"],                    icon: "🛠️" },
        { to: "/reports",   text: "Báo cáo",    roles: ["ADMIN","ACCOUNTANT"],       icon: "📑" },
    ];

    const visible = items.filter(i => can(...i.roles));

    return (
        <aside className="w-64 shrink-0 border-r bg-white">
            <div className="p-4">
                <div className="font-semibold text-slate-700">Quản lý KH & HĐ</div>
                <div className="text-xs text-slate-500">Bản React</div>
            </div>
            <nav className="px-2 space-y-1">
                {visible.map(i => (
                    <NavLink
                        key={i.to}
                        to={i.to}
                        end={i.to === "/"}
                        className={({ isActive }) =>
                            `flex items-center gap-2 px-3 py-2 rounded-lg text-sm
               ${isActive ? "bg-indigo-600 text-white" : "text-slate-700 hover:bg-indigo-50"}`
                        }
                    >
                        <span className="w-5">{i.icon}</span>
                        <span>{i.text}</span>
                    </NavLink>
                ))}
            </nav>
        </aside>
    );
}
